module top_module (
    input clk,
    input reset_n,
    input d,
    output q,
    output q_bar);reg obf_q_reg;

always @(posedge clk or negedge reset_n) begin
    if (~reset_n)
        obf_q_reg <= 1'b0;
    else
        obf_q_reg <= d;
end

assign q = obf_q_reg;
assign q_bar = ~obf_q_reg;

endmodule
